+// =============================================================================
+// Strategies
+// =============================================================================
+
+fn arb_view() -> impl Strategy<Value = View> {
+    prop_oneof![
+        Just(View::Home),
+        Just(View::Panes),
+        Just(View::Events),
+        Just(View::Triage),
+        Just(View::History),
+        Just(View::Search),
+        Just(View::Help),
+        Just(View::Timeline),
+    ]
+}
+
+fn arb_count() -> impl Strategy<Value = usize> {
+    0..200usize
+}
+
+fn arb_printable_char() -> impl Strategy<Value = char> {
+    prop_oneof![
+        (b'a'..=b'z').prop_map(|b| b as char),
+        (b'A'..=b'Z').prop_map(|b| b as char),
+        (b'0'..=b'9').prop_map(|b| b as char),
+        Just('_'),
+        Just('-'),
+        Just('.'),
+    ]
+}
